begin;

create table if not exists public.btp_solution_industry_stat (
    stat_id bigint generated by default as identity primary key,
    year integer not null,
    section_code character varying(10) not null,
    section_name character varying(200) not null,
    stat_category character varying(50) not null,
    region_name character varying(100) not null,
    middle_industry_name character varying(300) not null default '',
    dimension_name character varying(150) not null,
    establishment_count integer,
    employee_count integer,
    establishment_count_suppressed boolean not null default false,
    employee_count_suppressed boolean not null default false,
    source_table_id character varying(50) not null default '',
    source_file_name character varying(500),
    source_row_number integer,
    source_column_name character varying(100) not null default '',
    constraint uk_btp_solution_industry_stat unique (year, section_code, stat_category, region_name, middle_industry_name, dimension_name, source_table_id)
);

comment on table public.btp_solution_industry_stat is 'BTP solution industry statistics seeded from KOSIS Excel files';
comment on column public.btp_solution_industry_stat.stat_category is 'Statistic category: ESTABLISHMENT_TYPE, EMPLOYEE_SIZE, DISTRICT, ORGANIZATION_FORM';

on conflict (year, section_code, stat_category, region_name, middle_industry_name, dimension_name, source_table_id) do update set
    section_name = excluded.section_name,
    establishment_count = excluded.establishment_count,
    employee_count = excluded.employee_count,
    establishment_count_suppressed = excluded.establishment_count_suppressed,
    employee_count_suppressed = excluded.employee_count_suppressed,
    source_file_name = excluded.source_file_name,
    source_row_number = excluded.source_row_number,
    source_column_name = excluded.source_column_name;

create index if not exists idx_btp_solution_industry_stat_section on public.btp_solution_industry_stat (section_code, year);
create index if not exists idx_btp_solution_industry_stat_category on public.btp_solution_industry_stat (stat_category, section_code, year);

commit;
